import math
import torch
import torch.nn as nn
import torch.nn.functional as F

CLIP_MEAN = [0.48145466, 0.4578275, 0.40821073]
CLIP_STD = [0.26862954, 0.26130258, 0.27577711]
IN_MEAN = [0.485, 0.456, 0.406]
IN_STD = [0.229, 0.224, 0.225]

def preprocess_for_clip(images, device='cuda'):
    x = images.float() / 255.0
    x = F.interpolate(x, size=(224, 224), mode='bicubic', align_corners=False)
    mean = torch.tensor(CLIP_MEAN).view(1, 3, 1, 1).to(x.device)
    std = torch.tensor(CLIP_STD).view(1, 3, 1, 1).to(x.device)
    x = (x - mean) / std
    return x

def preprocess_for_in(images, device='cuda'):
    x = images.float() / 255.0
    x = F.interpolate(x, size=(224, 224), mode='bicubic', align_corners=False)
    mean = torch.tensor(IN_MEAN).view(1, 3, 1, 1).to(x.device)
    std = torch.tensor(IN_STD).view(1, 3, 1, 1).to(x.device)
    x = (x - mean) / std
    return x

class CosineClassifier(nn.Module):
    def __init__(self, in_features, num_classes):
        super().__init__()
        self.weight = nn.Parameter(torch.randn(num_classes, in_features))
        nn.init.xavier_uniform_(self.weight)
        self.scale = nn.Parameter(torch.tensor(10.0))

    def forward(self, x):
        x = F.normalize(x, dim=1)
        w = F.normalize(self.weight, dim=1)
        return self.scale * x @ w.t()

class FeatureExtractor(nn.Module):
    def __init__(self, model_name, layer_indices, preprocess_fn):
        super().__init__()
        import timm
        self.vit = timm.create_model(model_name, pretrained=True, num_classes=0)
        self.embed_dim = self.vit.num_features
        self.layer_indices = layer_indices
        self.preprocess_fn = preprocess_fn
        for p in self.vit.parameters():
            p.requires_grad = False
        self._intermediate = {}
        self._hooks = []
        self._register_hooks()

    def _register_hooks(self):
        for idx in self.layer_indices:
            def make_hook(i):
                def hook(module, input, output):
                    self._intermediate[i] = output[:, 0].clone()
                return hook
            h = self.vit.blocks[idx].register_forward_hook(make_hook(idx))
            self._hooks.append(h)

    def _collect_features(self, final_feat):
        feats = []
        for idx in sorted(self.layer_indices):
            if idx in self._intermediate:
                feats.append(self._intermediate[idx])
        feats.append(final_feat)
        return torch.cat(feats, dim=1)

    @property
    def feat_dim(self):
        return self.embed_dim * (len(self.layer_indices) + 1)

    def extract_features(self, images, device='cuda', batch_size=256):
        self.eval()
        all_features = []
        with torch.no_grad():
            for i in range(0, len(images), batch_size):
                batch = images[i:i+batch_size].to(device)
                batch = self.preprocess_fn(batch, device)
                self._intermediate = {}
                final_feat = self.vit(batch)
                multi_feat = self._collect_features(final_feat)
                all_features.append(multi_feat.cpu())
        return torch.cat(all_features, dim=0)

class DualModelClassifier(nn.Module):
    """Cosine classifier with 3-layer MLP and 2 residual connections"""
    def __init__(self, total_feat_dim, hidden_dim=2048, num_classes=100):
        super().__init__()
        self.fc1 = nn.Linear(total_feat_dim, hidden_dim)
        self.bn1 = nn.BatchNorm1d(hidden_dim)
        self.fc2 = nn.Linear(hidden_dim, hidden_dim)
        self.bn2 = nn.BatchNorm1d(hidden_dim)
        self.fc3 = nn.Linear(hidden_dim, hidden_dim)
        self.bn3 = nn.BatchNorm1d(hidden_dim)
        self.drop = nn.Dropout(0.3)
        self.cosine = CosineClassifier(hidden_dim, num_classes)

    def forward(self, x):
        x = self.drop(F.gelu(self.bn1(self.fc1(x))))
        residual = x
        x = self.drop(F.gelu(self.bn2(self.fc2(x))))
        x = x + residual
        residual2 = x
        x = self.drop(F.gelu(self.bn3(self.fc3(x))))
        x = x + residual2
        return self.cosine(x)
